41:    fn from_workspace_root_with_override(
42:        workspace_root: PathBuf,
43:        override_root: Option<PathBuf>,
44:    ) -> Result<Self, io::Error> {
45:        let workspace_root = absolutize(workspace_root)?;
46:        let configured =
47:            override_root.unwrap_or_else(|| PathBuf::from(RUNTIME_GOVERNANCE_DEFAULT_ROOT));
48:        if has_parent_dir(&configured) {
49:            return Err(io::Error::new(
50:                io::ErrorKind::InvalidInput,
51:                "runtime governance root must not contain '..' segments",
52:            ));
53:        }
54:
55:        let governance_root = if configured.is_absolute() {
56:            configured
57:        } else {
58:            workspace_root.join(configured)
59:        };
60:        let governance_root = absolutize(governance_root)?;
61:
62:        ensure_runtime_boundary(&workspace_root, &governance_root)?;
63:
64:        Ok(Self {
65:            workspace_root,
66:            governance_root,
67:        })
68:    }
