323:async fn dependency_would_create_cycle(
324:    pool: &SqlitePool,
325:    from_wp_id: &str,
326:    to_wp_id: &str,
327:) -> StorageResult<bool> {
328:    if from_wp_id == to_wp_id {
329:        return Ok(true);
330:    }
331:
332:    // Adding edge from -> to creates a cycle if there is already a path to -> ... -> from.
333:    let sql = r#"
334:        WITH RECURSIVE reach(wp_id) AS (
335:            SELECT to_wp_id FROM dependencies WHERE from_wp_id = $1
336:            UNION
337:            SELECT d.to_wp_id FROM dependencies d
338:            INNER JOIN reach r ON d.from_wp_id = r.wp_id
339:        )
340:        SELECT 1 FROM reach WHERE wp_id = $2 LIMIT 1;
341:    "#;
342:    let found = sqlx::query_scalar::<_, i64>(sql)
343:        .bind(to_wp_id)
344:        .bind(from_wp_id)
345:        .fetch_optional(pool)
346:        .await?
347:        .is_some();
348:
349:    Ok(found)
350:}
