424:async fn update_wp(pool: &SqlitePool, params: LocusUpdateWpParams) -> StorageResult<Value> {
425:    ensure_wp_exists(pool, &params.wp_id).await?;
426:
427:    let now = now_rfc3339();
428:
429:    let mut cols: Vec<(&'static str, Value)> = Vec::new();
430:    for (key, value) in params.updates {
431:        let col = match key.as_str() {
432:            "title" => "title",
433:            "description" => "description",
434:            "priority" => "priority",
435:            "status" => "status",
436:            "assignee" => "assignee",
437:            "governance.phase" | "phase" => "phase",
438:            "governance.routing" | "routing" => "routing",
439:            "governance.task_packet_path" | "task_packet_path" => "task_packet_path",
440:            "governance.task_board_status" | "task_board_status" => "task_board_status",
441:            other => {
442:                return Err(StorageError::Validation(match other {
443:                    "" => "empty update key",
444:                    _ => "unsupported update key",
445:                }));
446:            }
447:        };
448:        cols.push((col, value));
449:    }
450:
451:    if cols.is_empty() {
452:        return Ok(json!({
453:            "wp_id": params.wp_id,
454:            "updated_at": now,
455:            "no_op": true,
456:        }));
457:    }
458:
459:    let mut sql = String::from("UPDATE work_packets SET version = version + 1, updated_at = $1");
460:    for (idx, (col, _)) in cols.iter().enumerate() {
461:        sql.push_str(", ");
462:        sql.push_str(col);
463:        sql.push_str(" = $");
464:        sql.push_str(&(idx + 2).to_string());
465:    }
466:    sql.push_str(" WHERE wp_id = $");
467:    sql.push_str(&(cols.len() + 2).to_string());
468:
469:    let mut query = sqlx::query(&sql).bind(&now);
470:    for (col, value) in cols {
471:        match col {
472:            "priority" => match value {
473:                Value::Number(n) => {
474:                    let prio = n
475:                        .as_i64()
476:                        .ok_or(StorageError::Validation("priority must be an integer"))?;
477:                    if !(0..=4).contains(&prio) {
478:                        return Err(StorageError::Validation("priority must be between 0 and 4"));
479:                    }
480:                    query = query.bind(prio);
481:                }
482:                _ => return Err(StorageError::Validation("priority must be an integer")),
483:            },
484:            _ => match value {
485:                Value::String(s) => query = query.bind(s),
486:                Value::Null => query = query.bind(Option::<String>::None),
487:                _ => return Err(StorageError::Validation("unsupported update value type")),
488:            },
489:        }
490:    }
491:    query = query.bind(&params.wp_id);
492:
493:    let result = query.execute(pool).await?;
494:    if result.rows_affected() == 0 {
495:        return Err(StorageError::NotFound("work_packet"));
496:    }
497:
498:    Ok(json!({
499:        "wp_id": params.wp_id,
500:        "updated_at": now,
501:    }))
502:}
