27:    profile: ModelProfile,
28:    responses: Mutex<VecDeque<String>>,
29:    swap_calls: Mutex<Vec<ModelSwapRequestV0_4>>,
30:    swap_delay_ms: u64,
31:    swap_error: Option<String>,
32:}
33:
34:impl QueuedLlmClient {
35:    fn new(responses: Vec<String>) -> Self {
36:        Self {
37:            profile: ModelProfile::new("queued-test-model".to_string(), 4096),
38:            responses: Mutex::new(responses.into_iter().collect()),
39:            swap_calls: Mutex::new(Vec::new()),
40:            swap_delay_ms: 0,
41:            swap_error: None,
42:        }
43:    }
44:
45:    fn with_swap_delay_ms(mut self, swap_delay_ms: u64) -> Self {
46:        self.swap_delay_ms = swap_delay_ms;
47:        self
48:    }
49:
50:    fn with_swap_error(mut self, swap_error: impl Into<String>) -> Self {
51:        self.swap_error = Some(swap_error.into());
52:        self
53:    }
54:
55:    fn next_response(&self) -> String {
56:        let mut guard = self.responses.lock().expect("queued llm mutex poisoned");
57:        guard
58:            .pop_front()
59:            .unwrap_or_else(|| "<mt_complete>yes</mt_complete>".to_string())
60:    }
61:}
