63:#[async_trait]
64:impl LlmClient for QueuedLlmClient {
65:    async fn completion(&self, _req: CompletionRequest) -> Result<CompletionResponse, LlmError> {
66:        let text = self.next_response();
67:        Ok(CompletionResponse {
68:            text,
69:            usage: TokenUsage {
70:                prompt_tokens: 10,
71:                completion_tokens: 5,
72:                total_tokens: 15,
73:            },
74:            latency_ms: 0,
75:        })
76:    }
77:
78:    async fn swap_model(&self, req: ModelSwapRequestV0_4) -> Result<(), LlmError> {
79:        {
80:            let mut guard = self.swap_calls.lock().expect("swap_calls mutex poisoned");
81:            guard.push(req);
82:        }
83:
84:        if self.swap_delay_ms > 0 {
85:            tokio::time::sleep(Duration::from_millis(self.swap_delay_ms)).await;
86:        }
87:
88:        if let Some(err) = &self.swap_error {
89:            return Err(LlmError::ProviderError(err.clone()));
90:        }
91:
92:        Ok(())
93:    }
94:
95:    fn profile(&self) -> &ModelProfile {
96:        &self.profile
97:    }
98:}
