128:            trace_id: Uuid::new_v4(),
129:            job_kind: JobKind::LocusOperation,
130:            protocol_id: protocol_id.to_string(),
131:            profile_id: "default".to_string(),
132:            capability_profile_id: "Coder".to_string(),
133:            access_mode: AccessMode::AnalysisOnly,
134:            safety_mode: SafetyMode::Normal,
135:            entity_refs: Vec::new(),
136:            planned_operations: Vec::new(),
137:            status_reason: "queued".to_string(),
138:            metrics: JobMetrics::zero(),
139:            job_inputs: Some(inputs),
140:        })
141:        .await?;
142:    let job_id = job.job_id;
143:
144:    start_workflow_for_job(state, job).await?;
145:
146:    let updated_job = state.storage.get_ai_job(&job_id.to_string()).await?;
147:    assert!(
148:        matches!(
149:            updated_job.state,
150:            JobState::Completed | JobState::CompletedWithIssues
