106:fn status_for_heading(heading: &str) -> Option<TaskBoardStatus> {
107:    let heading = heading.trim();
108:    let heading = heading.strip_prefix("## ")?;
109:    let title = heading.trim();
110:
111:    if title.eq_ignore_ascii_case("Ready for Dev") {
112:        return Some(TaskBoardStatus::Ready);
113:    }
114:    if title.eq_ignore_ascii_case("In Progress") {
115:        return Some(TaskBoardStatus::InProgress);
116:    }
117:    if title.eq_ignore_ascii_case("Blocked") {
118:        return Some(TaskBoardStatus::Blocked);
119:    }
120:    if title.eq_ignore_ascii_case("Done") {
121:        return Some(TaskBoardStatus::Done);
122:    }
123:    if title.to_ascii_lowercase().starts_with("stub backlog") {
124:        return Some(TaskBoardStatus::Unknown);
125:    }
126:    if title.to_ascii_lowercase().starts_with("superseded") {
127:        return Some(TaskBoardStatus::Cancelled);
128:    }
129:
130:    None
131:}
