133:fn parse_entry_line(line: &str) -> Option<(String, String)> {
134:    let line = line.trim();
135:    if !line.starts_with("- **[") {
136:        return None;
137:    }
138:    let after_prefix = line.strip_prefix("- **[")?;
139:    let (wp_id, rest) = after_prefix.split_once("]**")?;
140:    let rest = rest.trim_start();
141:    let rest = rest.strip_prefix("-")?.trim_start();
142:    let token_part = rest.strip_prefix("[")?;
143:    let (token, _rest) = token_part.split_once(']')?;
144:    Some((wp_id.trim().to_string(), token.trim().to_string()))
145:}
