147:pub fn parse_task_board(markdown: &str) -> TaskBoardSections {
148:    let mut sections = TaskBoardSections::default();
149:    let mut current: Option<TaskBoardStatus> = None;
150:
151:    for raw_line in markdown.lines() {
152:        let line = raw_line.trim_end();
153:        if let Some(status) = status_for_heading(line) {
154:            current = Some(status);
155:            continue;
156:        }
157:
158:        let Some(status) = current else { continue };
159:        let Some((wp_id, token)) = parse_entry_line(line) else {
160:            continue;
161:        };
162:
163:        sections
164:            .entries_for_status_mut(status)
165:            .push(TaskBoardEntry {
166:                wp_id,
167:                token,
168:                status,
169:            });
170:    }
171:
172:    sections
173:}
