180:struct SectionWindow {
181:    status: TaskBoardStatus,
182:    start: usize,
183:}
184:
185:fn find_section_windows(lines: &[String]) -> Vec<SectionWindow> {
186:    let mut headings: Vec<(usize, TaskBoardStatus)> = Vec::new();
187:    for (idx, line) in lines.iter().enumerate() {
188:        if let Some(status) = status_for_heading(line) {
189:            headings.push((idx, status));
190:        }
191:    }
192:
193:    let mut windows: Vec<SectionWindow> = Vec::new();
194:    for (start, status) in headings {
195:        windows.push(SectionWindow { status, start });
196:    }
197:    windows
198:}
