200:pub fn rewrite_task_board(markdown: &str, canonical: &TaskBoardSections) -> String {
201:    let mut lines: Vec<String> = markdown.lines().map(|l| l.to_string()).collect();
202:
203:    let mut windows = find_section_windows(&lines);
204:    windows.sort_by(|a, b| b.start.cmp(&a.start));
205:
206:    for window in windows {
207:        let mut end = lines.len();
208:        for i in (window.start + 1)..lines.len() {
209:            if lines[i].trim_start().starts_with("## ") {
210:                end = i;
211:                break;
212:            }
213:        }
214:
215:        let mut entries: Vec<TaskBoardEntry> = canonical
216:            .entries_for_status(window.status)
217:            .iter()
218:            .cloned()
219:            .collect();
220:        entries.sort_by(|a, b| a.wp_id.cmp(&b.wp_id).then_with(|| a.token.cmp(&b.token)));
221:        let mut new_lines: Vec<String> = entries.iter().map(format_entry).collect();
222:
223:        let mut insert_at = end;
224:        for i in (window.start + 1)..end {
225:            if parse_entry_line(&lines[i]).is_some() {
226:                insert_at = i;
227:                break;
228:            }
229:        }
230:
231:        let mut i = window.start + 1;
232:        while i < end && i < lines.len() {
233:            if lines[i].trim_start().starts_with("## ") {
234:                break;
235:            }
236:            if parse_entry_line(&lines[i]).is_some() {
237:                lines.remove(i);
238:                end = end.saturating_sub(1);
239:                if i < insert_at {
240:                    insert_at = insert_at.saturating_sub(1);
241:                }
242:                continue;
243:            }
244:            i += 1;
245:        }
246:
247:        if !new_lines.is_empty() && insert_at == end {
248:            if insert_at > 0 && !lines[insert_at.saturating_sub(1)].trim().is_empty() {
249:                new_lines.insert(0, String::new());
250:            }
251:        }
252:
253:        lines.splice(insert_at..insert_at, new_lines);
254:    }
255:
256:    let mut out = lines.join("\n");
257:    if !out.ends_with('\n') {
258:        out.push('\n');
259:    }
260:    out
261:}
